mapper.select:
SELECT
FROM orders LEFT JOIN users ON users.id = orders.user_id
ORDER BY CASE orders.status WHEN 'PENDING_PAYMENT' THEN 1 WHEN 'PENDING_SHIPMENT' THEN 2 WHEN 'RETURN_REQUESTED' THEN 3 WHEN 'RETURN_APPROVED' THEN 4 WHEN 'RETURN_SHIPPED' THEN 5 WHEN 'SHIPPED' THEN 6 WHEN 'COMPLETED' THEN 7 WHEN 'RETURNED' THEN 8 WHEN 'REFUNDED' THEN 9 WHEN 'CANCELLED' THEN 10 ELSE 99 END, orders.created_at DESC, orders.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT

FROM orders
LEFT JOIN users ON users.id = orders.user_id
WHERE orders.user_id = #{userId}
ORDER BY orders.created_at DESC, orders.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM orders
WHERE user_id = #{userId}

SELECT DISTINCT o.*
FROM orders o
INNER JOIN order_items oi ON oi.order_id = o.id
WHERE o.user_id = #{userId}
  AND o.status = 'COMPLETED'
  AND o.created_at >= #{cutoff}
  AND oi.product_id = #{productId}
  AND NOT EXISTS (
      SELECT 1
      FROM reviews r
      WHERE r.order_id = o.id
        AND r.product_id = #{productId}
        AND r.user_id = #{userId}
  )
ORDER BY o.created_at DESC, o.id DESC
LIMIT #{limit}

SELECT * FROM orders
WHERE status = 'PENDING_PAYMENT'
  AND created_at <= #{cutoff}

  AND id > #{afterId}

ORDER BY id ASC
LIMIT #{limit}

mapper.update:
UPDATE orders
SET status = 'RETURN_APPROVED',
    return_approved_at = NOW(),
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}

UPDATE orders
SET status = #{status},
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}

UPDATE orders
SET status = 'REFUNDED',
    return_reason = CASE
        WHEN #{reason} IS NULL OR #{reason} = '' THEN return_reason
        ELSE #{reason}
    END,
    refunded_at = NOW(),
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}
